#include <stdio.h>
int main(void) {
    int x = 42;
    int *p = &x;
    printf("Valeur de x : %d\n", x);
    printf("Valeur via *p : %d\n", *p);
    printf("Adresses egales : %d\n", (p == &x));
    return 0;
}

starter_code_stages:
#include <stdio.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    int x = 42;       // ★ variable en pile
    int *p = &x;      // ★ & = opérateur adresse, p pointe vers x
    printf("Valeur de x : %d\n", x);
    printf("Valeur via *p : %d\n", *p); // ★ * déréférence
    printf("Adresses egales : %d\n", (p == &x)); // ★ p contient &x
    return 0;
}

